import math

# 输入获取
n = int(input())


# 素数判定
def isPrime(n):
    if n <= 3:
        return n > 1

    if n % 6 != 1 and n % 6 != 5:
        return False

    for i in range(5, int(math.sqrt(n)) + 1, 6):
        if n % i == 0 or n % (i + 2) == 0:
            return False

    return True


# 算法入口
def getResult(n):
    # 如果n为素数,则必然不可能是两个素数之积
    if isPrime(n):
        return "-1 -1"

    # 假设i为n的因子
    for i in range(2, n):
        # 若n不能整除i,则i不是n的因子,继续下次循环,找新的i
        # 若n可以整除i,则i就是n的因子
        if n % i == 0:
            # j为n的另一因子
            j = n // i
            # 只有i,j因子都为素数时,n才是符合题意的素数之积
            if isPrime(i) and isPrime(j):
                # 如果n为两个素数之积,则n只能分解为这两个因子,因为素数无法再次分解出其他因子,也就是说n不再有其他因子了&#xff08;因子不包含1和自身&#xff09;
                return f"{i} {j}" if i < j else f"{j} {i}"
            else:
                # 如果i,j有一个不是素数因子,则说明n存在非素数因子,此时n不可能是素数之积
                # 如果i,j为相同的素数因子,则n不是满足题意的素数之积
                # 此时可以判定n不符合要求了,直接退出循环
                break

    return "-1 -1"


# 算法调用
print(getResult(n))
